{
  "intent": "check_and_fix",
  "intent_description": "Restore IP reachability between 192.168.0.12 and 172.16.0.12 (25 ICMP probes from 192.168.0.12 to 172.16.0.12 all failed). Desired outcome: hosts on 192.168.0.0/24 and 172.16.0.0/24 can reach each other.",
  "target": null,
  "needs_fix": true,
  "plan": {
    "problem": "ICMP from 192.168.0.12 to 172.16.0.12 failing (25/25 lost). Likely missing IP routes between 192.168.0.0/24 and 172.16.0.0/24 on the edge routers.",
    "fix_summary": "Add static routes on router1 and router2 so each LAN has a route to the opposite LAN via the router-to-router transit link (assume transit 10.0.0.0/30 with router1=10.0.0.1 and router2=10.0.0.2).",
    "plan_steps": [
      {
        "id": 1,
        "device": "router1",
        "action": "add_static_route",
        "target": "172.16.0.0/24",
        "parameters": [
          "prefix=172.16.0.0/24",
          "next_hop=10.0.0.2"
        ]
      },
      {
        "id": 2,
        "device": "router2",
        "action": "add_static_route",
        "target": "192.168.0.0/24",
        "parameters": [
          "prefix=192.168.0.0/24",
          "next_hop=10.0.0.1"
        ]
      }
    ]
  }
}

